import hou
# ── 1. Build staircase geometry via detail-class attribwrangle ────────
geo = hou.node('/obj').createNode('geo', 'staircase_build')
w = geo.createNode('attribwrangle', 'stair_gen')
w.parm('class').set(1)  # detail class
snippet = """
int   n  = chi('step_count');
float sw = chf('step_width');
float sd = chf('step_depth');
float sh = chf('step_height');
for (int i = 0; i < n; i++) {
    // Tread (horizontal face)
    vector p0 = set(0,   i*sh,       i*sd);
    vector p1 = set(sw,  i*sh,       i*sd);
    vector p2 = set(sw,  i*sh,  (i+1)*sd);
    vector p3 = set(0,   i*sh,  (i+1)*sd);
    int a0=addpoint(0,p0), a1=addpoint(0,p1),
        a2=addpoint(0,p2), a3=addpoint(0,p3);
    addprim(0,'poly', a0,a1,a2,a3);
    // Riser (vertical face)
    vector r0 = set(0,   i*sh,  (i+1)*sd);
    vector r1 = set(sw,  i*sh,  (i+1)*sd);
    vector r2 = set(sw, (i+1)*sh,(i+1)*sd);
    vector r3 = set(0,  (i+1)*sh,(i+1)*sd);
    int b0=addpoint(0,r0), b1=addpoint(0,r1),
        b2=addpoint(0,r2), b3=addpoint(0,r3);
    addprim(0,'poly', b0,b1,b2,b3);
}
"""
w.parm('snippet').set(snippet)
out = geo.createNode('null', 'OUT')
out.setInput(0, w)
geo.layoutChildren()

# ── 2. Package as HDA ─────────────────────────────────────────────────
subnet = hou.node('/obj').createNode('subnet', 'staircase_subnet')
hda_node = subnet.createDigitalAsset(
    name='staircase_hda',
    hda_file_name='$HOME/houdini20.5/otls/staircase_hda.hda',
    description='Procedural Straight Staircase'
)
hda_def = hda_node.type().definition()
ptg = hda_def.parmTemplateGroup()
ptg.append(hou.IntParmTemplate(
    'step_count', 'Step Count', 1,
    default_value=(12,), min=2, max=50
))
ptg.append(hou.FloatParmTemplate(
    'step_width', 'Step Width', 1,
    default_value=(1.2,), min=0.3, max=5.0
))
ptg.append(hou.FloatParmTemplate(
    'step_depth', 'Step Depth', 1,
    default_value=(0.28,), min=0.1, max=1.0
))
ptg.append(hou.FloatParmTemplate(
    'step_height', 'Step Height', 1,
    default_value=(0.18,), min=0.05, max=0.5
))
hda_def.setParmTemplateGroup(ptg)
hda_def.save(hda_def.libraryFilePath())
print('Staircase HDA:', hda_def.libraryFilePath())

import hou
geo = hou.node('/obj').createNode('geo', 'staircase_railing_build')

# ── Stair treads + risers (same as HDA_Architecture_StraightStaircase) ─
stair = geo.createNode('attribwrangle', 'stair_gen')
stair.parm('class').set(1)
stair.parm('snippet').set("""
int n=chi('step_count'); float sw=chf('step_width');
float sd=chf('step_depth'); float sh=chf('step_height');
for(int i=0;i<n;i++){
  int a0=addpoint(0,set(0,i*sh,i*sd)), a1=addpoint(0,set(sw,i*sh,i*sd)),
      a2=addpoint(0,set(sw,i*sh,(i+1)*sd)), a3=addpoint(0,set(0,i*sh,(i+1)*sd));
  addprim(0,'poly',a0,a1,a2,a3);
  int b0=addpoint(0,set(0,i*sh,(i+1)*sd)), b1=addpoint(0,set(sw,i*sh,(i+1)*sd)),
      b2=addpoint(0,set(sw,(i+1)*sh,(i+1)*sd)), b3=addpoint(0,set(0,(i+1)*sh,(i+1)*sd));
  addprim(0,'poly',b0,b1,b2,b3);
}
""")

# ── Handrail path (polyline along the stair nose) ──────────────────────
rail_pts = geo.createNode('attribwrangle', 'rail_path_pts')
rail_pts.parm('class').set(1)
rail_pts.parm('snippet').set("""
int n=chi('step_count'); float sd=chf('step_depth');
float sh=chf('step_height'); float rh=chf('rail_height');
// Left rail path
for(int i=0;i<=n;i++){
  int p=addpoint(0,set(0,i*sh+rh,i*sd));
  if(i>0)addprim(0,'polyline',p-1,p);
}
// Right rail path (offset by step_width)
for(int i=0;i<=n;i++){
  int p=addpoint(0,set(chf('step_width'),i*sh+rh,i*sd));
  if(i>0)addprim(0,'polyline',p-1,p);
}
""")

# PolyWire to give rails thickness
pw = geo.createNode('polywire', 'rail_tube')
pw.parm('wire_radius').setExpression("ch('../rail_radius')")
pw.setInput(0, rail_pts)

# ── Spindles ───────────────────────────────────────────────────────────
spindle_geo = geo.createNode('tube', 'spindle_templ')
spindle_geo.parm('rad1').setExpression("ch('../spindle_radius')")
spindle_geo.parm('rad2').setExpression("ch('../spindle_radius')")
spindle_geo.parm('height').setExpression("ch('../rail_height')")

spindle_pts = geo.createNode('attribwrangle', 'spindle_pts')
spindle_pts.parm('class').set(1)
spindle_pts.parm('snippet').set("""
int n=chi('step_count'); int sp=chi('spindle_count');
float sd=chf('step_depth'); float sh=chf('step_height');
for(int i=0;i<n;i++){
  for(int j=0;j<sp;j++){
    float u=(j+0.5)/sp;
    addpoint(0,set(0,   i*sh+sh*0.5, (i+u)*sd));
    addpoint(0,set(chf('step_width'),i*sh+sh*0.5,(i+u)*sd));
  }
}
""")

cp = geo.createNode('copytopoints', 'copy_spindles')
cp.setInput(0, spindle_geo)
cp.setInput(1, spindle_pts)

# ── Merge + switch on has_railing ──────────────────────────────────────
m_full = geo.createNode('merge', 'merge_full')
m_full.setInput(0, stair)
m_full.setInput(1, pw)
m_full.setInput(2, cp)

sw = geo.createNode('switch', 'railing_switch')
sw.parm('input').setExpression("chi('../has_railing')")
sw.setInput(0, stair)    # has_railing=0: stairs only
sw.setInput(1, m_full)   # has_railing=1: stairs + railing

out = geo.createNode('null', 'OUT')
out.setInput(0, sw)
geo.layoutChildren()

# ── Package as HDA ─────────────────────────────────────────────────────
subnet = hou.node('/obj').createNode('subnet', 'staircase_railing_subnet')
hda = subnet.createDigitalAsset(
    name='staircase_railing_hda',
    hda_file_name='$HOME/houdini20.5/otls/staircase_railing_hda.hda',
    description='Procedural Staircase with Railing'
)
hda_def = hda.type().definition()
ptg = hda_def.parmTemplateGroup()

# Stair parms
stair_folder = hou.FolderParmTemplate('stair_tab','Staircase',folder_type=hou.folderType.Tabs)
stair_folder.addParmTemplate(hou.IntParmTemplate('step_count','Step Count',1,default_value=(12,),min=2,max=50))
stair_folder.addParmTemplate(hou.FloatParmTemplate('step_width','Step Width',1,default_value=(1.2,),min=0.3,max=5.0))
stair_folder.addParmTemplate(hou.FloatParmTemplate('step_depth','Step Depth',1,default_value=(0.28,),min=0.1,max=1.0))
stair_folder.addParmTemplate(hou.FloatParmTemplate('step_height','Step Height',1,default_value=(0.18,),min=0.05,max=0.5))
ptg.append(stair_folder)

# Railing parms
rail_folder = hou.FolderParmTemplate('rail_tab','Railing',folder_type=hou.folderType.Tabs)
rail_folder.addParmTemplate(hou.ToggleParmTemplate('has_railing','Include Railing',default_value=True))
rail_folder.addParmTemplate(hou.FloatParmTemplate('rail_height','Handrail Height',1,default_value=(0.9,),min=0.5,max=1.5))
rail_folder.addParmTemplate(hou.FloatParmTemplate('rail_radius','Rail Tube Radius',1,default_value=(0.025,),min=0.005,max=0.08))
rail_folder.addParmTemplate(hou.IntParmTemplate('spindle_count','Spindles per Step',1,default_value=(2,),min=1,max=5))
rail_folder.addParmTemplate(hou.FloatParmTemplate('spindle_radius','Spindle Radius',1,default_value=(0.01,),min=0.003,max=0.05))
ptg.append(rail_folder)

hda_def.setParmTemplateGroup(ptg)
hda_def.save(hda_def.libraryFilePath())
print('Staircase+Railing HDA:', hda_def.libraryFilePath())
